const payload  = $('Incoming Payload').first().json;
const orders   = $('Fetch Customer Orders').all().map(i => i.json).filter(o => o && o.order_number);
const rawText  = payload.question_text || '';
const isOrderFollowUp = /pending order|follow.?up|still waiting|unconfirmed/i.test(rawText)
  || /MSQ-[A-Z0-9]+/.test(rawText);

let enrichedText = rawText;

if (isOrderFollowUp && orders.length > 0) {
  const orderLines = orders.map(o => {
    let itemsText = '';
    try {
      const items = typeof o.items === 'string' ? JSON.parse(o.items) : (o.items || []);
      if (Array.isArray(items) && items.length) {
        itemsText = items.map(i => {
          const qty   = i.quantity > 1 ? i.quantity + 'x ' : '';
          const price = i.unit_price ? ' @ \u20a6' + Number(i.unit_price).toLocaleString() : '';
          return qty + i.name + price;
        }).join(', ');
      }
    } catch(e) {}

    const hours = Math.round(o.hours_ago || 0);
    const timeLabel = hours < 1 ? 'just now'
      : hours < 24 ? hours + 'h ago'
      : Math.round(hours / 24) + 'd ago';

    const total = o.total_amount
      ? ' \u2014 Total: \u20a6' + Number(o.total_amount).toLocaleString()
      : '';

    return `• ${o.order_number} (${o.status}, placed ${timeLabel})${total}${itemsText ? '\n  Items: ' + itemsText : ''}`;
  }).join('\n');

  const count = orders.length;
  enrichedText = count === 1
    ? `A customer is following up on an unconfirmed order:\n${orderLines}\nPlease confirm or respond.`
    : `A customer is following up on ${count} unconfirmed orders:\n${orderLines}\nPlease attend to these.`;
}

return [{ json: {
  enriched_text:     enrichedText,
  is_order_followup: isOrderFollowUp && orders.length > 0,
  orders:            isOrderFollowUp ? orders : [],
  tenant_id:         payload.tenant_id,
  business_id:       payload.business_id,
  customer_chat_id:  payload.customer_chat_id,
  customer_name:     payload.customer_name,
  bot_token:         payload.bot_token,
  question_text:     payload.question_text,
  business_name:     payload.business_name
}}];

