parameters.jsonBody:
={{ (function() {
  const enriched   = $('Enrich With Order Details').first().json;
  const escalation = $('Save Escalation to DB').first().json;
  const photos     = $('Fetch Product Photos').all().map(i => i.json).filter(p => p && p.minio_url);
  const text       = enriched.enriched_text || '';
  const isOrder    = /MSQ-[A-Z0-9]+/.test(text) || /unconfirmed order/i.test(text);

  const header = isOrder
    ? '\u23f3 *Order needs your attention*'
    : '\u2753 *Customer message needs your response*';

  const replyMarkup = JSON.stringify({
    inline_keyboard: [[
      { text: '\u270f\ufe0f Reply to customer', callback_data: 'escalation_reply|' + escalation.escalation_id },
      { text: '\u2716 Ignore',                  callback_data: 'escalation_ignore|' + escalation.escalation_id }
    ]]
  });

  const fullText = header + '\n\n' + text + '\n\n_Tap to act:_';

  if (photos.length === 1) {
    // Single product — send photo with caption
    return {
      chat_id:      String(escalation.owner_telegram_id),
      photo:        photos[0].minio_url,
      caption:      fullText,
      parse_mode:   'Markdown',
      reply_markup: replyMarkup
    };
  }

  // Multiple products or no photos — send text with photo links
  let photoLinks = '';
  if (photos.length > 1) {
    photoLinks = '\n\n*Products:* ' + photos.map(p =>
      '[' + p.product_name + '](' + p.minio_url + ')'
    ).join(' \u00b7 ');
  }

  return {
    chat_id:                String(escalation.owner_telegram_id),
    text:                   fullText + photoLinks,
    parse_mode:             'Markdown',
    disable_web_page_preview: false,
    reply_markup:           replyMarkup
  };
})() }}

